 Example 2: Multiple Object Detection 
 #include "ZebraHuskyLens.h" 
 ZebraHuskyLens  husky  (4, 0)  ; 
 void  setup  ()  { 
 Serial.begin(  115200  ); 
 if  (!husky.begin()) { 
 Serial.println(  "HuskyLens initialization failed!"  ); 
 while  (  1  ); 
 } 
 Serial.println(  "Multiple Object Detection Ready"  ); 
 } 
 void  loop  ()  { 
 if  (husky.update()) { 
 int  count = husky.getObjectCount(); 
 if  (count >  0  ) { 
 Serial.  printf  (  "Detected %d objects\n"  , count); 
 for  (  int  i =  0  ; i < count; i++) { 
 Serial.  printf  ( 
 "Object %d: ID=%d, X=%d, Y=%d\n"  , 
 i +  1  , 
 husky.getID(i), 
 husky.getX(i), 
 husky.getY(i) 
 ); 
 } 
 } 
 } 
 delay(  500  ); 
 } 
